        stem = raw.strip()
        if stem.lower().endswith(".json"):
            stem = stem[:-5]
        bad = '<>:"/\\|?*'
        return "".join("_" if c in bad else c for c in stem)

    def _resolve_model_paths(self, mode_suffix: str) -> Tuple[Path, Path]:
